8	const CURSE_SURCHARGE = 0.5;
9	const FIRST_INSURANCE_SURCHARGE = 0.1;
10	const FOLLOW_UP_CONTRACT_DISCOUNT = 0.15;
11	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
12	const HIGH_ENCHANTMENT_THRESHOLD = 5;
13	const LOYALTY_DISCOUNT = 0.2;
14	const LOYALTY_YEARS_THRESHOLD = 2;
