57	const PROCESSING_FEE = 5;
58	
59	const BASE_PREMIUM: Record<string, number> = {
60	  sword: 100,
61	  amulet: 60,
62	  staff: 80,
63	  potion: 40,
64	  rune: 25,
65	  moonstone: 25,
66	};
67	
68	const INSURANCE_VALUE: Record<string, number> = {
69	  sword: 1000,
70	  amulet: 600,
71	  staff: 800,
72	  potion: 400,
73	  rune: 250,
74	  moonstone: 250,
75	};
