77	const DEDUCTIBLE = 100;
78	const CAP_MULTIPLIER = 2;
79	
80	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
81	
82	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
83	const COMPONENT_BLOCK_SIZE = 3;
84	const COMPONENT_BLOCK_PRICE = 60;
85	
86	const groupByType = (items: Item[]): Map<string, Item[]> => {
87	  const groups = new Map<string, Item[]>();
88	  for (const item of items) {
89	    const group = groups.get(item.type) ?? [];
90	    group.push(item);
91	    groups.set(item.type, group);
92	  }
93	  return groups;
94	};
95	
96	const isHighlyEnchanted = (item: Item): boolean =>
97	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
98	
99	const itemSurchargeFactor = (item: Item): number =>
100	  (item.cursed ? CURSE_SURCHARGE : 0) +
101	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
102	
103	const itemSurchargeAmount = (item: Item): number =>
104	  basePremiumFor(item) * itemSurchargeFactor(item);
105	
106	const groupBaseCost = (type: string, group: Item[]): number => {
107	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
108	    return COMPONENT_BLOCK_PRICE;
109	  }
110	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
111	};
112	
113	const policyBase = (items: Item[]): number =>
114	  Array.from(groupByType(items)).reduce(
115	    (sum, [type, group]) => sum + groupBaseCost(type, group),
116	    0,
117	  );
118	
119	const itemSurchargesTotal = (items: Item[]): number =>
120	  items.reduce((sum, item) => sum + itemSurchargeAmount(item), 0);
121	
122	const policyModifierFactor = (
123	  customer: { yearsWithMHPCO: number },
124	  isFollowUp: boolean,
125	): number =>
126	  FIRST_INSURANCE_SURCHARGE -
127	  (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 0) -
128	  (isFollowUp ? FOLLOW_UP_CONTRACT_DISCOUNT : 0);
129	
130	const quote = (
131	  items: Item[],
132	  customer: { yearsWithMHPCO: number },
133	  isFollowUp: boolean,
134	): QuoteResult => {
135	  const base = policyBase(items);
136	  const itemSurcharges = itemSurchargesTotal(items);
137	  const policyModifiers = base * policyModifierFactor(customer, isFollowUp);
138	  return {
139	    premium: Math.ceil(base + itemSurcharges + policyModifiers + PROCESSING_FEE),
140	  };
141	};
