143	interface Policy {
144	  items: Item[];
145	  insuranceSum: number;
146	  remainingCap: number;
147	}
148	
149	const policyInsuranceSum = (items: Item[]): number =>
150	  items.reduce((sum, item) => sum + (INSURANCE_VALUE[item.type] ?? 0), 0);
151	
152	const createPolicy = (items: Item[]): Policy => {
153	  const insuranceSum = policyInsuranceSum(items);
154	  return {
155	    items,
156	    insuranceSum,
157	    remainingCap: insuranceSum * CAP_MULTIPLIER,
158	  };
159	};
