161	const processClaim = (policy: Policy, step: ClaimStep): ClaimResult => {
162	  const payout = step.incident.damages.reduce(
163	    (sum, damage) => sum + Math.max(0, damage.amount - DEDUCTIBLE),
164	    0,
165	  );
166	  policy.remainingCap -= payout;
167	  return { payout, remainingCap: policy.remainingCap };
168	};
