170	export const runScenario = (scenario: Scenario): ScenarioResult => {
171	  const policies: Policy[] = [];
172	  let quoteCount = 0;
173	  const results: StepResult[] = scenario.steps.map((step) => {
174	    if (step.op === "quote") {
175	      const isFollowUp = quoteCount > 0;
176	      quoteCount += 1;
177	      policies.push(createPolicy(step.items));
178	      return quote(step.items, scenario.customer, isFollowUp);
179	    }
180	    return processClaim(policies[step.policy], step);
181	  });
182	  return { results };
183	};
